const msg = $input.first().json.message;
const jobId = 'AIH-' + Date.now();

let inputType = 'topic';
let inputValue = '';
let fileId = null;
let fileName = null;

if (msg.document) {
  inputType = 'pdf';
  fileId = msg.document.file_id;
  fileName = msg.document.file_name || 'notification.pdf';
  inputValue = fileName;
} else if (msg.text) {
  const text = msg.text.trim();
  if (/^https?:\/\//i.test(text)) {
    inputType = 'url';
    inputValue = text;
  } else {
    inputType = 'topic';
    inputValue = text;
  }
}

const payload = {
  job: {
    id: jobId,
    chatId: msg.chat.id,
    inputType: inputType,
    inputValue: inputValue,
    fileId: fileId,
    fileName: fileName,
    receivedAt: new Date().toISOString(),
    status: 'received',
    retryCounts: { research: 0, blog: 0, seo: 0, social: 0, gdocs: 0, telegram: 0 }
  },
  research: {},
  article: {},
  seo: {},
  social: {},
  thumbnail: {},
  schema: {},
  output: {}
};

return [{ json: payload }];

const job = $('02 - Build Standard Job Payload').first().json;
const httpResult = $input.first().json;

let webpageContent = '';
if (job.job.inputType === 'url' && httpResult && httpResult.data) {
  webpageContent = String(httpResult.data).slice(0, 15000);
} else if (job.job.inputType === 'url' && typeof httpResult === 'string') {
  webpageContent = httpResult.slice(0, 15000);
}

job.research.rawWebpageContent = webpageContent;
return [{ json: job }];

const job = $('04 - Merge Webpage Content Into Payload').first().json;
const aiResponse = $input.first().json;

function extractText(resp) {
  if (resp && resp.content && Array.isArray(resp.content)) {
    return resp.content.map(b => b.text || '').join('\n');
  }
  if (resp && resp.candidates) {
    return resp.candidates[0]?.content?.parts?.map(p => p.text).join('\n') || '';
  }
  if (typeof resp === 'string') return resp;
  return JSON.stringify(resp);
}

let text = extractText(aiResponse).trim();
text = text.replace(/^```json/i, '').replace(/^```/, '').replace(/```$/, '').trim();

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  parsed = { verified: false, parseError: true, rawText: text.slice(0, 2000) };
}

job.research = Object.assign({}, job.research, parsed);
job.job.status = 'research_complete';
return [{ json: job }];

