// Combine SEO branch (index 0) and Social branch (index 1) back into one job object
const items = $input.all();
let seoJob = null;
let socialJob = null;

for (const it of items) {
  if (it.json.seo) seoJob = it.json;
  if (it.json.social) socialJob = it.json;
}

const base = seoJob || socialJob;
const merged = Object.assign({}, base, {
  seo: seoJob ? seoJob.seo : {},
  schema: seoJob ? seoJob.schema : {},
  social: socialJob ? socialJob.social : {}
});
merged.job.status = 'ready_for_doc_assembly';
return [{ json: merged }];

const job = $input.first().json;
const a = job.article || {};
const s = job.seo || {};
const soc = job.social || {};

function block(title, content) {
  if (!content) return '';
  return '\n\n' + title.toUpperCase() + '\n' + '-'.repeat(title.length) + '\n' + (Array.isArray(content) ? content.join('\n') : String(content));
}

const thumbnailPrompt = `Create a clean, modern, mobile-friendly thumbnail for a ${s.category || 'government jobs'} blog post titled "${a.heroTitle || ''}". Bold Telugu+English title text, AIH brand colors, official/trustworthy visual style, 1280x720, no clutter.`;

let doc = '';
