doc += block('Secondary Keywords', s.secondaryKeywords);
doc += block('Tags', s.tags);
doc += block('Category', s.category);
doc += block('Excerpt', s.excerpt);
doc += block('Reading Time (minutes)', s.readingTimeMinutes);
doc += block('Image ALT', s.imageAlt);

doc += '\n\n=== BLOG ARTICLE ===';
doc += block('Hero Title', a.heroTitle);
doc += block('Quick Summary', a.quickSummary);
doc += block('Table of Contents', a.tableOfContents);
doc += block('Introduction', a.introduction);
doc += block('Latest Update', a.latestUpdate);
doc += block('Overview', a.overview);
doc += block('Highlights', a.highlights);
doc += block('Eligibility', a.eligibility);
doc += block('Vacancy', a.vacancy);
doc += block('Age Limit', a.ageLimit);
doc += block('Qualification', a.qualification);
doc += block('Salary', a.salary);
doc += block('Benefits', a.benefits);
doc += block('Application Fee', a.applicationFee);
doc += block('Selection Process', a.selectionProcess);
doc += block('Exam Pattern', a.examPattern);
doc += block('Syllabus', a.syllabus);
doc += block('Documents', a.documents);
doc += block('Application Process', a.applicationProcess);
doc += block('Important Dates', a.importantDates);
doc += block('Instructions', a.instructions);
doc += block('Mistakes to Avoid', a.mistakesToAvoid);
if (a.faqs && a.faqs.length) {
  doc += '\n\nFAQS\n----\n';
  a.faqs.forEach(f => { doc += 'Q: ' + f.question + '\nA: ' + f.answer + '\n\n'; });
}
doc += block('Official Website', a.officialWebsite);
doc += block('Official Notification', a.officialNotification);
doc += block('Apply Link', a.applyLink);
doc += block('Related Articles', a.relatedArticles);
doc += block('Conclusion', a.conclusion);
doc += block('AIH Tip', a.aihTip);
doc += block('Reminder', a.reminder);

doc += '\n\n=== THUMBNAIL PROMPT ===\n' + thumbnailPrompt;

doc += '\n\n=== SOCIAL MEDIA ===';
doc += block('Instagram', soc.instagram);
doc += block('Facebook', soc.facebook);
doc += block('Telegram', soc.telegram);
doc += block('WhatsApp', soc.whatsapp);
doc += block('LinkedIn', soc.linkedin);
doc += block('Threads', soc.threads);
doc += block('Twitter / X', soc.twitter);
doc += block('Pinterest', soc.pinterest);
doc += block('YouTube Description', soc.youtubeDescription);
doc += block('YouTube Community', soc.youtubeCommunity);

doc += '\n\n=== SCHEMA (JSON-LD) ===\n' + JSON.stringify(job.schema || {}, null, 2);

doc += '\n\n=== QUALITY CHECKLIST ===\n';
doc += '[ ] Official Source Verified\n[ ] Human Written\n[ ] Beginner Friendly\n[ ] SEO Optimized\n';
doc += '[ ] Google Discover Ready\n[ ] Rank Math Ready\n[ ] Mobile Friendly\n[ ] WordPress Ready\n';
doc += '[ ] Tables Added\n[ ] FAQs Added\n[ ] Schema Added\n[ ] Internal Links Suggested\n';
doc += '[ ] Official Links Only\n[ ] Social Media Generated\n[ ] Thumbnail Prompt Generated\n';

job.output.googleDocContent = doc;
job.output.thumbnailPrompt = thumbnailPrompt;
job.output.docTitle = (a.heroTitle || job.job.inputValue || job.job.id) + ' | AIH';

const now = new Date();
job.output.yearFolderName = String(now.getFullYear());
const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
job.output.monthFolderName = monthNames[now.getMonth()];

return [{ json: job }];

const job = $('15 - Assemble Google Doc Content').first().json;
